* QAGR -- result screen rendered after QAGE. Display-only fields
* (PROT INPUTs are filled by Go via FROM(SCR.) substitution).
MAP QAGR1 SIZE 24x80
  FIELD AT 0,2  LEN 30 PROT BRIGHT COLOR=BLUE  "Query Your Age - Result"
  FIELD AT 0,60 LEN 5  PROT COLOR=BLUE         "TERM="
  INPUT TERMID  AT 0,65 LEN 8  PROT COLOR=BLUE
  FIELD AT 4,4  LEN 12 PROT COLOR=BLUE         "Birthdate :"
  INPUT BIRTH   AT 4,18 LEN 12 PROT BRIGHT COLOR=GREEN
  FIELD AT 6,4  LEN 12 PROT COLOR=BLUE         "Age       :"
  INPUT AGE     AT 6,18 LEN 16 PROT BRIGHT COLOR=GREEN
  FIELD AT 8,4  LEN 12 PROT COLOR=BLUE         "Days alive:"
  INPUT DAYS    AT 8,18 LEN 12 PROT BRIGHT COLOR=GREEN
  FIELD AT 22,2 LEN 50 PROT COLOR=BLUE         "Press ENTER or PF3 to return to the prompt."
ENDMAP
